#include <stdio.h>
#include <stdbool.h>
#define MAX_SIZE 1000001
const long long mod = 1e9 + 7;
const long long inf = 1e18;
// Function to initialize isPrime and smallestPrimeFactor arrays
void sieve(bool isPrime[], int smallestPrimeFactor[]) {
    isPrime[0] = false; // 0 is not prime
    isPrime[1] = false; // 1 is not prime
    for (int i = 2; i < MAX_SIZE; i++) {
        isPrime[i] = true; // Assume all numbers are prime initially
    }

    for (int i = 2; i < MAX_SIZE; i++) {
        if (isPrime[i]) {
            smallestPrimeFactor[i] = i; // Initialize smallest prime factor
            for (int j = i * 2; j < MAX_SIZE; j += i) {
                isPrime[j] = false; // Mark multiples of i as non-prime
                if (smallestPrimeFactor[j] == 0) {
                    smallestPrimeFactor[j] = i; // Update smallest prime factor
                }
            }
        }
    }
}

int main() {
    bool isPrime[MAX_SIZE];
    int smallestPrimeFactor[MAX_SIZE];
    sieve(isPrime, smallestPrimeFactor); // Precompute primes

    int t;
    scanf("%d", &t); // Read number of test cases

    while (t--) {
        int n;
        scanf("%d", &n); // Read size of the array
        int cnt[MAX_SIZE] = {0}; // Array to count occurrences of prime factors

        for (int i = 0; i < n; i++) {
            int x;
            scanf("%d", &x); // Read each number
            while (x > 1) {
                cnt[smallestPrimeFactor[x]]++; // Count the prime factor
                x /= smallestPrimeFactor[x]; // Divide x by its smallest prime factor
            }
        }

        long long ans = 1; // Initialize answer
        for (int i = 2; i < MAX_SIZE; i++) {
            if (cnt[i] > 0) {
                ans *= (cnt[i] + 1); // Calculate the product of (count + 1)
            }
        }
        printf("%lld\n", ans); // Output the result for the current test case
    }
    return 0;
}

