import java.util.*;

class Main {
    static final long MOD = 1000000007;
    static final long INF = 1000000000000000000L;
    static final int MAX_SIZE = 1000001;

    // Function to initialize isPrime and smallestPrimeFactor arrays
    static void sieve(boolean[] isPrime, int[] smallestPrimeFactor) {
        Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false; // 0 and 1 are not prime
        for (int i = 2; i < MAX_SIZE; i++) {
            if (isPrime[i]) {
                smallestPrimeFactor[i] = i; // Initialize smallest prime factor
                for (int j = i * 2; j < MAX_SIZE; j += i) {
                    isPrime[j] = false; // Mark multiples of i as non-prime
                    if (smallestPrimeFactor[j] == 0) {
                        smallestPrimeFactor[j] = i; // Update smallest prime factor
                    }
                }
            }
        }
    }

    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);
        boolean[] isPrime = new boolean[MAX_SIZE];
        int[] smallestPrimeFactor = new int[MAX_SIZE];
        sieve(isPrime, smallestPrimeFactor); // Precompute primes

        int t = scanner.nextInt(); // Read number of test cases

        while (t-- > 0) {
            int n = scanner.nextInt(); // Read size of the array
            Map<Integer, Integer> cnt = new HashMap<>(); // Map to count occurrences of prime factors

            for (int i = 0; i < n; i++) {
                int x = scanner.nextInt(); // Read each number
                while (x > 1) {
                    cnt.put(smallestPrimeFactor[x], cnt.getOrDefault(smallestPrimeFactor[x], 0) + 1); // Count the prime factor
                    x /= smallestPrimeFactor[x]; // Divide x by its smallest prime factor
                }
            }

            long ans = 1; // Initialize answer
            for (int value : cnt.values()) {
                ans = (ans * (value + 1)) % MOD; // Calculate the product of (count + 1)
            }
            System.out.println(ans); // Output the result for the current test case
        }
        scanner.close(); // Close the scanner
    }
}

