def sieve(max_size):
    is_prime = [True] * (max_size + 1)
    smallest_prime_factor = [0] * (max_size + 1)
    is_prime[0] = is_prime[1] = False  # 0 and 1 are not prime

    for i in range(2, max_size + 1):
        if is_prime[i]:
            smallest_prime_factor[i] = i  # Initialize smallest prime factor
            for j in range(i * 2, max_size + 1, i):
                is_prime[j] = False  # Mark multiples of i as non-prime
                if smallest_prime_factor[j] == 0:
                    smallest_prime_factor[j] = i  # Update smallest prime factor

    return smallest_prime_factor

def main():
    max_size = 10**6
    smallest_prime_factor = sieve(max_size)  # Precompute smallest prime factors

    t = int(input())  # Read number of test cases
    results = []

    for _ in range(t):
        n = int(input())  # Read size of the array
        count = {}  # Dictionary to count occurrences of prime factors

        x_values = list(map(int, input().split()))  # Read each number

        for x in x_values:
            while x > 1:
                spf = smallest_prime_factor[x]  # Get smallest prime factor
                count[spf] = count.get(spf, 0) + 1  # Count the prime factor
                x //= spf  # Divide x by its smallest prime factor

        ans = 1  # Initialize answer
        for freq in count.values():
            ans *= (freq + 1)  # Calculate the product of (count + 1)

        results.append(ans)  # Store the result for the current test case

    # Output all results, each on a new line
    print('\n'.join(map(str, results)))

if __name__ == "__main__":
    main()

