            const spf = smallestPrimeFactor[x];
            cnt.set(spf, (cnt.get(spf) || 0) + 1); // Count the prime factor
            x /= spf; // Divide x by its smallest prime factor
        }
    });

    let ans = 1; // Initialize answer
    for (const count of cnt.values()) {
        ans *= (count + 1); // Calculate the product of (count + 1)
    }
    output += ans + '\n'; // Store the result for the current test case
}
